<section class="admin-page-head"><div><p class="eyebrow">SEO</p><h1>Manager redirecturi</h1><p>Redirecturile sunt verificate contra buclelor înainte de salvare.</p></div></section><?php if($notice): ?><div class="admin-alert success"><?= e($notice) ?></div><?php endif; ?><div class="admin-two-columns"><section class="admin-panel"><div class="admin-table-wrap"><table class="admin-table"><thead><tr><th>Sursă</th><th>Țintă</th><th>Cod</th><th>Accesări</th></tr></thead><tbody><?php foreach($items as $item): ?><tr><td><?= e($item['source_path']) ?></td><td><?= e($item['target_path']?:'Pagină eliminată') ?></td><td><?= (int)$item['http_status'] ?></td><td><?= (int)$item['hit_count'] ?></td></tr><?php endforeach; ?></tbody></table></div></section><aside><form class="admin-panel" method="post" action="<?= e(url('/admin/seo/redirecturi')) ?>"><?= csrf_field() ?><h2>Redirect nou</h2><label>Cale veche<input name="source_path" required placeholder="/pagina-veche"></label><label>Cale nouă<input name="target_path" placeholder="/pagina-noua"></label><label>Cod<select name="http_status"><option value="301">301 permanent</option><option value="302">302 temporar</option><option value="410">410 eliminat</option></select></label><label>Motiv<textarea name="reason"></textarea></label><button class="admin-button" type="submit">Salvează redirectul</button></form></aside></div>
